function generateId() {
    return 'req_' + Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15);
}

function redactObject(obj) {
    if (!obj || typeof obj !== 'object') {
        return obj;
    }

    const sensitiveKeys = [
        'password', 'senha', 'token', 'api_key', 'apikey', 'secret', 
        'authorization', 'cookie', 'smtp_password', 'imap_password', 
        'jwt', 'bearer', 'access_token', 'refresh_token', 'private_key', 
        'client_secret'
    ];

    if (Array.isArray(obj)) {
        return obj.map(item => redactObject(item));
    }

    const redacted = {};
    for (const key in obj) {
        if (obj.hasOwnProperty(key)) {
            const lowerKey = key.toLowerCase();
            const isSensitive = sensitiveKeys.some(sKey => lowerKey.includes(sKey));

            if (isSensitive) {
                redacted[key] = '[REDACTED]';
            } else if (typeof obj[key] === 'object') {
                redacted[key] = redactObject(obj[key]);
            } else {
                redacted[key] = obj[key];
            }
        }
    }
    return redacted;
}

const items = $input.all();
const results = [];

let envRuntimeMode = "";
try {
    if (typeof $env !== 'undefined' && $env.VESPER_RUNTIME_MODE) {
        envRuntimeMode = $env.VESPER_RUNTIME_MODE;
    }
} catch (e) {}

for (const item of items) {
    const json = item.json;
    let rawInput = {};
    if (json.error && json.workflow) {
        rawInput = {
            runtime_mode: json.runtime_mode || envRuntimeMode || "MOCK",
            source: "n8n",
            workflow: json.workflow.name || "",
            failed_node: json.error.node?.name || "",
            error_message: json.error.message || "",
            error_stack: json.error.stack || "",
            payload_summary: json.execution || {},
            input: json.error.node?.parameters || {}
        };
    } else if (json.query && Object.keys(json.query).length > 0) {
        rawInput = json.query;
    } else if (json.body && Object.keys(json.body).length > 0) {
        rawInput = json.body;
    } else {
        rawInput = json;
    }

    let runtimeMode = (rawInput.runtime_mode || envRuntimeMode || "TESTE").toUpperCase();
    if (!["TESTE", "MOCK", "PORTAL"].includes(runtimeMode)) {
        runtimeMode = "TESTE";
    }

    const correlationId = rawInput.correlation_id || rawInput.correlationId || generateId();
    const requestId = rawInput.request_id || rawInput.requestId || generateId();

    const source = rawInput.source || "n8n";
    const workflowName = rawInput.workflow || "Unknown Workflow";
    const agent = rawInput.agent || "core";
    const moduleName = rawInput.module || rawInput.module_hint || "";
    const failedNode = rawInput.failed_node || rawInput.failedNode || "";
    const errorMessage = rawInput.error_message || rawInput.message || "";
    const errorStack = rawInput.error_stack || "";
    const retryCount = parseInt(rawInput.retry_count || rawInput.retryCount || 0, 10);

    const user = rawInput.user || { id: "", name: "", role: "", department: "" };

    const defaultRiskContext = {
        customer_related: false,
        supplier_related: false,
        financial_related: false,
        external_email_related: false,
        security_related: false,
        production_related: false,
        ex_inmetro_related: false
    };
    const inputRisk = rawInput.risk_context || rawInput.riskContext || {};
    const riskContext = {};
    for (const key in defaultRiskContext) {
        let val = inputRisk[key];
        if (val === undefined) {
            val = rawInput[`risk_context[${key}]`] || rawInput[`riskContext[${key}]`];
        }
        if (val === 'true' || val === true || val === 1 || val === '1') {
            riskContext[key] = true;
        } else {
            riskContext[key] = false;
        }
    }

    const redactedInput = redactObject(rawInput.input || rawInput.payload || {});
    const redactedPayloadSummary = redactObject(rawInput.payload_summary || {});
    const redactedErrorMessage = typeof errorMessage === 'string' ? redactObject({msg: errorMessage}).msg : errorMessage;
    const redactedErrorStack = typeof errorStack === 'string' ? redactObject({stack: errorStack}).stack : errorStack;

    let severity = "low";
    let isCritical = false;
    let isHigh = false;

    const criticalKeywords = [
        'credential', 'vazamento', 'senha', 'password', 'key_leak', 
        'ex_inmetro', 'inmetro', 'compliance', 'exclusao', 'delete', 'drop'
    ];

    const containsCriticalKeyword = 
        criticalKeywords.some(kw => redactedErrorMessage?.toLowerCase().includes(kw)) ||
        criticalKeywords.some(kw => redactedErrorStack?.toLowerCase().includes(kw));

    if (riskContext.security_related || riskContext.ex_inmetro_related || containsCriticalKeyword) {
        severity = "critical";
        isCritical = true;
    } else if (
        riskContext.customer_related || 
        riskContext.supplier_related || 
        riskContext.financial_related || 
        riskContext.external_email_related || 
        riskContext.production_related
    ) {
        severity = "high";
        isHigh = true;
    } else if (errorMessage && errorMessage.trim().length > 0) {
        severity = "medium";
    }

    let retryable = false;
    const nonRetryableKeywords = ['auth', 'unauthorized', 'forbidden', 'credential', 'validation', 'syntax', 'not found', 'invalid'];
    const isNonRetryable = nonRetryableKeywords.some(kw => redactedErrorMessage?.toLowerCase().includes(kw));

    if (!isCritical && !isNonRetryable && retryCount < 3) {
        retryable = true;
    }

    let status = "logged";
    let deadLetterStatus = "";
    let nextAction = "none";

    if (severity === "critical" || severity === "high") {
        status = "manual_review";
        deadLetterStatus = "waiting_review";
        nextAction = "manual_review";
    } else if (retryable) {
        status = "retry_pending";
        deadLetterStatus = "retry_scheduled";
        nextAction = "retry_pending";
    } else if (severity === "medium") {
        status = "dead_letter";
        deadLetterStatus = "dead_letter";
        nextAction = "none";
    }

    const missingFields = [];
    if (!rawInput.workflow) missingFields.push("workflow");
    if (!rawInput.error_message && !rawInput.message) missingFields.push("error_message");

    results.push({
        json: {
            correlation_id: correlationId,
            request_id: requestId,
            status: status,
            agent: "core",
            workflow: "CORE - Error Audit Dead Letter",
            summary: `Error captured, redacted, classified as ${severity} and stored.`,
            data: {
                source_workflow: workflowName,
                failed_node: failedNode,
                severity: severity,
                retryable: retryable,
                retry_count: retryCount,
                dead_letter_status: deadLetterStatus,
                portal_synced: false,
                source: source,
                module: moduleName,
                error_message: redactedErrorMessage,
                error_stack: redactedErrorStack,
                risk_context: riskContext,
                payload_summary: redactedPayloadSummary,
                input: redactedInput,
                user: user
            },
            missing_fields: missingFields,
            requires_approval: (severity === "critical" || severity === "high"),
            approval_id: (severity === "critical" || severity === "high") ? "appr_" + generateId().substring(4) : null,
            risk_level: severity,
            next_action: nextAction,
            runtime_mode: runtimeMode
        }
    });
}

return results;

return [{
  json: {
    ...$input.item.json,
    db_logs_mocked: true,
    db_logs_table: "vesper_agent_logs",
    dead_letter_mocked: true,
    dead_letter_table: "vesper_dead_letters",
    message: "TESTE Mode: No real actions performed. Logs simulated in mock tables."
  }
}];

return [{
  json: {
    ...$input.item.json,
    mock_saved: true,
    saved_to_dead_letters: $input.item.json.next_action === 'retry_pending' || $input.item.json.risk_level === 'medium',
    saved_to_agent_logs: true,
    message: "MOCK Mode: Simulated Portal payload. Stored locally in virtual Data Tables."
  }
}];

const item = $input.first();
const data = item.json;

return [{
  json: {
    status: data.status || "success",
    agent: data.agent || "core",
    workflow: data.workflow || "CORE - Error Audit Dead Letter",
    correlation_id: data.correlation_id || "",
    request_id: data.request_id || "",
    next_action: data.next_action || "none",
    timestamp: new Date().toISOString(),
    runtime_mode: data.runtime_mode || "TESTE",
    data: data.data || {}
  }
}];

